export const DEFAULT_REGION = {
  state: 'Tamil Nadu',
  district: 'Chennai',
  area: 'T Nagar'
};

export const getDistricts = (state) => Object.keys(REGION_TREE[state] || {});
export const getAreas = (state, district) => {
  const areas = Object.keys(REGION_TREE[state]?.[district] || {});
  return areas.sort(); // Return alphabetically sorted for easier UI use
};

export const getAreaConfig = (state, district, area) =>
  REGION_TREE[state]?.[district]?.[area] || REGION_TREE[DEFAULT_REGION.state][DEFAULT_REGION.district][DEFAULT_REGION.area];

/**
 * Finds the state, district, and area that contains the given coordinate.
 * Falls back to null if the coordinate is outside all defined areas.
 */
export const findAreaByCoordinate = (lng, lat) => {
  for (const state of Object.keys(REGION_TREE)) {
    for (const district of Object.keys(REGION_TREE[state])) {
      for (const area of Object.keys(REGION_TREE[state][district])) {
        const { bbox } = REGION_TREE[state][district][area];
        if (bbox) {
          const [minLng, minLat, maxLng, maxLat] = bbox;
          if (lng >= minLng && lng <= maxLng && lat >= minLat && lat <= maxLat) {
            return { state, district, area };
          }
        }
      }
    }
  }
  return null;
};
